/// Exhaustive coverage: every ClientFrame / ServerFrame arm appears in samples.
fn assert_client_sample_covers(frame: &ClientFrame) {
    match frame {
        ClientFrame::Hello { .. }
        | ClientFrame::Resize { .. }
        | ClientFrame::Input(_)
        | ClientFrame::Command(_)
        | ClientFrame::Detach
        | ClientFrame::FocusIn
        | ClientFrame::FocusOut
        | ClientFrame::ClipboardImage(_)
        | ClientFrame::ClipboardImageStart(_)
        | ClientFrame::ClipboardImageChunk(_)
        | ClientFrame::ClipboardImageEnd(_)
        | ClientFrame::ClipboardImageError(_)
        | ClientFrame::HostNotice(_) => {}
    }
}

fn assert_server_sample_covers(frame: &ServerFrame) {
    match frame {
        ServerFrame::Welcome { .. }
        | ServerFrame::Output(_)
        | ServerFrame::SessionList(_)
        | ServerFrame::Shutdown { .. }
        | ServerFrame::Bell
        | ServerFrame::HostOpenUrl(_)
        | ServerFrame::FileExportStart(_)
        | ServerFrame::FileExportChunk(_)
        | ServerFrame::FileExportEnd(_)
        | ServerFrame::HostRevealPath(_)
        | ServerFrame::HostStageImageFromClipboardPath
        | ServerFrame::HostPasteImageFromClipboard
        | ServerFrame::HostStageImageFromClipboard => {}
    }
}

#[test]
fn corpus_covers_every_client_and_server_frame_variant() {
    for (_, f) in client_samples() {
        assert_client_sample_covers(&f);
    }
    for (_, f) in server_samples() {
        assert_server_sample_covers(&f);
    }
    // Count arms via samples length vs hard minimum from enum census.
    assert!(client_samples().len() >= 13, "client samples incomplete");
    assert!(server_samples().len() >= 13, "server samples incomplete");
}

#[test]
fn golden_client_frames_round_trip_decode() {
    for (name, frame) in client_samples() {
        let bytes = attach::encode_client(frame.clone()).expect(name);
        assert!(!bytes.is_empty(), "{name}");
        let tag = bytes[0];
        let payload = bytes[5..].to_vec();
        let decoded = attach::decode_client(tag, payload)
            .unwrap_or_else(|e| panic!("{name}: decode failed: {e:#}"));
        // Detach/Focus are unit-like; compare via re-encode equality where PartialEq holds.
        assert_eq!(decoded, frame, "{name}");
        // truncations must fail closed
        for cut in [1usize, 3, bytes.len().saturating_sub(1).max(1)] {
            if cut >= bytes.len() {
                continue;
            }
            let partial = &bytes[..cut];
            if partial.is_empty() {
                continue;
            }
            let tag = partial[0];
            let payload = if partial.len() > 5 {
                partial[5..].to_vec()
            } else {
                vec![]
            };
            // short payload must not panic
            drop(attach::decode_client(tag, payload));
        }
    }
}

#[test]
fn golden_server_frames_round_trip_decode() {
    for (name, frame) in server_samples() {
        let bytes = attach::encode_server(frame.clone());
        assert!(!bytes.is_empty(), "{name}");
        let tag = bytes[0];
        let payload = bytes[5..].to_vec();
        let decoded = attach::decode_server(tag, payload)
            .unwrap_or_else(|e| panic!("{name}: decode failed: {e:#}"));
        assert_eq!(decoded, frame, "{name}");
        for cut in [1usize, 3, bytes.len().saturating_sub(1).max(1)] {
            if cut >= bytes.len() {
                continue;
            }
            let partial = &bytes[..cut];
            if partial.is_empty() {
                continue;
            }
            let tag = partial[0];
            let payload = if partial.len() > 5 {
                partial[5..].to_vec()
            } else {
                vec![]
            };
            drop(attach::decode_server(tag, payload));
        }
    }
}

/// Residual (plan 045 STOP): current Hello decoder hard-errors when the
/// focus/terminal capability tail is omitted ("hello payload ended before
/// focus kind"). Soft-default skew for older peers is not implemented yet;
/// this test pins fail-closed (clean Err, never panic) until a decoder change.
#[test]
fn skew_hello_without_trailing_capability_fields_fails_closed_cleanly() {
    let mut payload = Vec::new();
    payload.extend_from_slice(&24u16.to_be_bytes());
    payload.extend_from_slice(&80u16.to_be_bytes());
    payload.push(0); // spawn none
    payload.extend_from_slice(&0u16.to_be_bytes()); // agent len
    payload.extend_from_slice(&0u16.to_be_bytes()); // env count
    // no focus / terminal tail
    let err = attach::decode_client(attach::TAG_HELLO, payload)
        .expect_err("current decoder hard-errors on short Hello (skew residual)");
    let msg = format!("{err:#}");
    assert!(
        msg.contains("focus") || msg.contains("short") || msg.contains("ended"),
        "expected focus-tail/short error, got: {msg}"
    );
}

#[test]
fn skew_unknown_client_tag_0xfe_returns_clean_error() {
    let err = attach::decode_client(0xFE, vec![1, 2, 3]).expect_err("unknown tag must error");
    let msg = format!("{err:#}");
    assert!(
        msg.to_lowercase().contains("unknown") || msg.to_lowercase().contains("tag"),
        "error should name unknown tag: {msg}"
    );
}

#[test]
fn skew_unknown_server_tag_0xfe_returns_clean_error() {
    let err = attach::decode_server(0xFE, vec![1, 2, 3]).expect_err("unknown tag must error");
    let msg = format!("{err:#}");
    assert!(
        msg.to_lowercase().contains("unknown") || msg.to_lowercase().contains("tag"),
        "error should name unknown tag: {msg}"
    );
}

#[test]
#[ignore = "run manually to rewrite binary corpus fixtures under tests/corpus/"]
fn regenerate_corpus() {
    let dir = Path::new(env!("CARGO_MANIFEST_DIR")).join("tests/corpus");
    std::fs::create_dir_all(&dir).unwrap();
    for (name, frame) in client_samples() {
        let bytes = attach::encode_client(frame).unwrap();
        std::fs::write(dir.join(format!("{name}.bin")), bytes).unwrap();
    }
    for (name, frame) in server_samples() {
        let bytes = attach::encode_server(frame);
        std::fs::write(dir.join(format!("{name}.bin")), bytes).unwrap();
    }
}
